/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Features:
 * - Phone number validation: validates E.164-like format before delivery
 * - Message formatting: truncates/formats notification payload for SMS constraints
 * - Pluggable transport: swap SMS implementation for testing or real providers (Twilio, etc.)
 *
 * The adapter conforms to the NotificationAdapter interface and never throws —
 * all errors are captured in the NotificationResult.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

// ---------------------------------------------------------------------------
// SMS message types
// ---------------------------------------------------------------------------

/**
 * Represents a formatted SMS message ready for delivery.
 */
export interface SmsMessage {
  to: string;
  body: string;
  sentAt: Date;
}

// ---------------------------------------------------------------------------
// SMS transport
// ---------------------------------------------------------------------------

/**
 * Transport interface — abstracts the actual SMS sending mechanism.
 * Swap implementations for Twilio, AWS SNS, Vonage, etc.
 */
export interface SmsTransport {
  sendSms(message: SmsMessage): Promise<void>;
}

/**
 * In-memory transport that stores sent messages for inspection (testing / dev).
 */
export class InMemorySmsTransport implements SmsTransport {
  private sent: SmsMessage[] = [];

  async sendSms(message: SmsMessage): Promise<void> {
    this.sent.push(message);
  }

  getSentMessages(): SmsMessage[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

// ---------------------------------------------------------------------------
// SmsAdapter
// ---------------------------------------------------------------------------

/** Maximum SMS body length (standard single-segment SMS). */
const MAX_SMS_LENGTH = 160;

export interface SmsAdapterOptions {
  transport?: SmsTransport;
  maxLength?: number;
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private transport: SmsTransport;
  private maxLength: number;

  constructor(options: SmsAdapterOptions = {}) {
    this.transport = options.transport ?? new InMemorySmsTransport();
    this.maxLength = options.maxLength ?? MAX_SMS_LENGTH;
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // 1. Validate phone number
      const phoneNumber = payload.recipient;
      if (!isValidPhoneNumber(phoneNumber)) {
        this.logger.warn(`Invalid phone number: ${phoneNumber}`);
        return {
          notificationId: payload.id,
          channel: 'sms',
          success: false,
          error: `Invalid phone number: "${phoneNumber}"`,
          deliveredAt: new Date(),
        };
      }

      // 2. Format the SMS body (subject + body, truncated to max length)
      const fullText = `${payload.subject}: ${payload.body}`;
      const body = fullText.length > this.maxLength
        ? fullText.slice(0, this.maxLength - 3) + '...'
        : fullText;

      // 3. Build the SMS message
      const message: SmsMessage = {
        to: phoneNumber,
        body,
        sentAt: new Date(),
      };

      // 4. Send through the transport
      await this.transport.sendSms(message);

      this.logger.info(`SMS sent to ${phoneNumber}: ${payload.subject}`);

      return {
        notificationId: payload.id,
        channel: 'sms',
        success: true,
        deliveredAt: message.sentAt,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${errorMessage}`);

      return {
        notificationId: payload.id,
        channel: 'sms',
        success: false,
        error: errorMessage,
        deliveredAt: new Date(),
      };
    }
  }

  /** Get all sent messages (delegates to transport if it supports inspection). */
  getSentMessages(): SmsMessage[] {
    if (this.transport instanceof InMemorySmsTransport) {
      return this.transport.getSentMessages();
    }
    return [];
  }

  /** Clear sent messages (delegates to transport if it supports it). */
  clearSentMessages(): void {
    if (this.transport instanceof InMemorySmsTransport) {
      this.transport.clear();
    }
  }
}

// ---------------------------------------------------------------------------
// Utility
// ---------------------------------------------------------------------------

/**
 * Validates a phone number in E.164 format: + followed by 7-15 digits.
 */
function isValidPhoneNumber(phone: string): boolean {
  return /^\+[1-9]\d{6,14}$/.test(phone);
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsAdapter,
  InMemorySmsTransport,
} from '../../src/adapters/sms.adapter.js';
import type {
  SmsTransport,
  SmsMessage,
} from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'sms',
    recipient: '+15551234567',
    subject: 'Order Confirmation',
    body: 'Your order has been placed.',
    priority: 'normal',
    createdAt: new Date('2026-01-01'),
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let transport: InMemorySmsTransport;
  let adapter: SmsAdapter;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
    adapter = new SmsAdapter({ transport });
  });

  describe('channel', () => {
    it('should report channel as sms', () => {
      expect(adapter.channel).toBe('sms');
    });
  });

  describe('send()', () => {
    it('should send an SMS and return a successful result', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('sms');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should deliver the message through the transport', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const messages = transport.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.to).toBe('+15551234567');
      expect(messages[0]?.body).toContain('Order Confirmation');
      expect(messages[0]?.body).toContain('Your order has been placed.');
    });

    it('should format body as subject + body', async () => {
      const payload = makePayload({
        subject: 'Test Subject',
        body: 'Test body content',
      });
      await adapter.send(payload);

      const messages = transport.getSentMessages();
      expect(messages[0]?.body).toBe('Test Subject: Test body content');
    });

    it('should truncate messages longer than max length', async () => {
      const longBody = 'A'.repeat(200);
      const payload = makePayload({ body: longBody });
      await adapter.send(payload);

      const messages = transport.getSentMessages();
      expect(messages[0]?.body.length).toBe(160);
      expect(messages[0]?.body).toMatch(/\.\.\.$/);
    });

    it('should respect custom max length', async () => {
      const shortAdapter = new SmsAdapter({ transport, maxLength: 50 });
      const payload = makePayload({
        subject: 'Subject',
        body: 'This is a message body that will be truncated to fit the limit',
      });
      await shortAdapter.send(payload);

      const messages = transport.getSentMessages();
      expect(messages[0]?.body.length).toBe(50);
      expect(messages[0]?.body).toMatch(/\.\.\.$/);
    });

    it('should not truncate messages within max length', async () => {
      const payload = makePayload({
        subject: 'Hi',
        body: 'Short',
      });
      await adapter.send(payload);

      const messages = transport.getSentMessages();
      expect(messages[0]?.body).toBe('Hi: Short');
    });

    it('should include metadata in payload but not in SMS body', async () => {
      const payload = makePayload({
        metadata: { orderId: 'order-1' },
      });
      await adapter.send(payload);

      const messages = transport.getSentMessages();
      expect(messages[0]?.body).not.toContain('order-1');
    });
  });

  describe('phone number validation', () => {
    it('should accept valid E.164 phone numbers', async () => {
      const payload = makePayload({ recipient: '+442071234567' });
      const result = await adapter.send(payload);
      expect(result.success).toBe(true);
    });

    it('should accept minimal E.164 numbers (7 digits)', async () => {
      const payload = makePayload({ recipient: '+1234567' });
      const result = await adapter.send(payload);
      expect(result.success).toBe(true);
    });

    it('should accept maximum E.164 numbers (15 digits)', async () => {
      const payload = makePayload({ recipient: '+123456789012345' });
      const result = await adapter.send(payload);
      expect(result.success).toBe(true);
    });

    it('should fail for numbers without + prefix', async () => {
      const payload = makePayload({ recipient: '15551234567' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
      expect(transport.getSentMessages()).toHaveLength(0);
    });

    it('should fail for non-numeric strings', async () => {
      const payload = makePayload({ recipient: 'not-a-phone' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should fail for email addresses', async () => {
      const payload = makePayload({ recipient: 'alice@example.com' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should fail for numbers starting with +0', async () => {
      const payload = makePayload({ recipient: '+0123456789' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should fail for too-short numbers', async () => {
      const payload = makePayload({ recipient: '+12345' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });
  });

  describe('error handling', () => {
    it('should return a failed result when transport throws', async () => {
      const failingTransport: SmsTransport = {
        async sendSms() {
          throw new Error('SMS gateway unavailable');
        },
      };

      const failAdapter = new SmsAdapter({ transport: failingTransport });
      const payload = makePayload();
      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMS gateway unavailable');
      expect(result.notificationId).toBe('notif-0001');
    });

    it('should handle non-Error thrown values', async () => {
      const failingTransport: SmsTransport = {
        async sendSms() {
          throw 'string error';
        },
      };

      const failAdapter = new SmsAdapter({ transport: failingTransport });
      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('string error');
    });
  });

  describe('getSentMessages / clearSentMessages', () => {
    it('should return sent messages from the in-memory transport', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ id: 'notif-0002', recipient: '+442071234567' }));

      expect(adapter.getSentMessages()).toHaveLength(2);
    });

    it('should clear sent messages', async () => {
      await adapter.send(makePayload());
      adapter.clearSentMessages();

      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should return empty array when transport is not InMemorySmsTransport', () => {
      const customTransport: SmsTransport = { async sendSms() {} };
      const customAdapter = new SmsAdapter({ transport: customTransport });

      expect(customAdapter.getSentMessages()).toEqual([]);
    });
  });
});

describe('InMemorySmsTransport', () => {
  let transport: InMemorySmsTransport;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
  });

  it('should store sent messages', async () => {
    const msg: SmsMessage = {
      to: '+15551234567',
      body: 'Test SMS',
      sentAt: new Date(),
    };
    await transport.sendSms(msg);

    expect(transport.getSentMessages()).toHaveLength(1);
    expect(transport.getSentMessages()[0]?.to).toBe('+15551234567');
  });

  it('should clear stored messages', async () => {
    await transport.sendSms({
      to: '+15551234567',
      body: 'Test',
      sentAt: new Date(),
    });
    transport.clear();
    expect(transport.getSentMessages()).toHaveLength(0);
  });
});

